    "express": "^4.18.2",
    "axios": "^1.6.0"
  }
}

const express = require('express');
const axios = require('axios');

const app = express();
const PORT = 3000;

// In-memory cache for NIN verification results
const ninCache = new Map();

// Middleware to parse JSON bodies
app.use(express.json());

// NIN verification endpoint
app.post('/api/verify-nin', async (req, res) => {
  try {
    const { nin } = req.body;

    // Validate NIN input
    if (!nin || typeof nin !== 'string' || nin.trim() === '') {
      return res.status(400).json({
        success: false,
        error: 'NIN is required and must be a non-empty string'
      });
    }

    const normalizedNin = nin.trim();

    // Check if NIN is already cached
    if (ninCache.has(normalizedNin)) {
      console.log(`Cache hit for NIN: ${normalizedNin}`);
      return res.json({
        success: true,
        cached: true,
        data: ninCache.get(normalizedNin)
      });
    }

    // Get environment variables
    const appId = process.env.PREMBLY_APP_ID;
    const apiKey = process.env.PREMBLY_API_KEY;

    if (!appId || !apiKey) {
      return res.status(500).json({
        success: false,
        error: 'PREMBLY_APP_ID and PREMBLY_API_KEY environment variables are required'
      });
    }

    console.log(`Cache miss for NIN: ${normalizedNin}. Fetching from Prembly API...`);

    // Make request to Prembly API
    const premblyResponse = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: normalizedNin },
      {
        headers: {
          'app-id': appId,
          'x-api-key': apiKey,
          'Content-Type': 'application/json'
        }
      }
    );

    // Cache the successful response data
    const responseData = premblyResponse.data;
    ninCache.set(normalizedNin, responseData);
    console.log(`Cached result for NIN: ${normalizedNin}`);

    // Return the response
    res.json({
      success: true,
      cached: false,
      data: responseData
    });

  } catch (error) {
    console.error('Error verifying NIN:', error.message);

    // Handle Axios errors
    if (error.response) {
      // The request was made and the server responded with a status code
      return res.status(error.response.status).json({
        success: false,
        error: error.response.data?.message || 'Prembly API error',
        details: error.response.data
      });
    } else if (error.request) {
      // The request was made but no response was received
      return res.status(503).json({
        success: false,
        error: 'Unable to connect to Prembly API'
      });
    } else {
      // Something happened in setting up the request
      return res.status(500).json({
        success: false,
        error: 'Internal server error'
      });
    }
  }
});

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({
    status: 'ok',
    cacheSize: ninCache.size,
    timestamp: new Date().toISOString()
  });
});

// Start the server
app.listen(PORT, () => {
  console.log(`NIN Verification Cache Server running on port ${PORT}`);
  console.log(`Health check available at http://localhost:${PORT}/health`);
  console.log(`Verify NIN endpoint at POST http://localhost:${PORT}/api/verify-nin`);
});

module.exports = app;

